<td>$22,000</td>
</tr>
<tr>
<td>Faculty of Applied Sciences</td>
<td>Hotel Management</td>
<td>$22,000</td>
</tr>
<tr>
<td>Faculty of Applied Sciences</td>
<td>Gastronomy and Culinary Arts</td>
<td>$22,000</td>
</tr>
<tr>
<td>Faculty of Architecture and Design</td>
<td>Architecture</td>
<td>$22,000</td>
</tr>
