<div class="min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-5" dir="auto" data-message-author-role="assistant" data-message-id="962f9996-c04c-4182-a10a-8d9aff32fb03" data-message-model-slug="gpt-4o">
